+                total_events: 10,
+                event_type_counts,
+                expected_decision_counts: BTreeMap::new(),
+                actual_decision_counts: BTreeMap::new(),
+                matched_events: 10 - mismatched_events,
+                mismatched_events,
+                matched_decisions: 8 - mismatched_decisions,
+                mismatched_decisions,
+            },
